mapper.select:
SELECT COUNT(*)
FROM   budgets
WHERE  user_id                        = #{userId}
  AND  COALESCE(category_id, -1)      = COALESCE(#{categoryId, jdbcType=BIGINT}, -1)
  AND  year_month                     = #{yearMonth}
  AND  deleted_at                    IS NULL

mapper.update:
UPDATE budgets
SET    amount     = #{amount},
       updated_at = NOW()
WHERE  id         = #{id}
  AND  user_id    = #{userId}
  AND  deleted_at IS NULL

UPDATE budgets
SET    deleted_at = NOW(),
       updated_at = NOW()
WHERE  id         = #{id}
  AND  user_id    = #{userId}
  AND  deleted_at IS NULL
